import{readFileSync}from"node:fs";import picomatch from"picomatch";import{debugLog}from"./debug.js";import{convertGitignoreToPicomatchIgnorePatterns}from"./parse-and-convert-gitignores.js";export function parseCodeowners(r){const e=r.split(/\r?\n/).filter(r=>r&&!r.startsWith("#")).map(r=>{const[e,...o]=r.split(/\s+/),{patterns:t}=convertGitignoreToPicomatchIgnorePatterns(e);return{owners:o,match:picomatch(t)}});return r=>{for(const o of[...e].reverse())if(o.match(r))return o.owners;return[]}}export function createOwnershipEngine(r){try{return parseCodeowners(readFileSync(r,"utf8"))}catch(e){throw debugLog("*",`Failed to load codeowners file from ${r}`),e}}